class TestCmdTest:
    def _require_axiom_rules_path(self) -> Path:
        candidates = (
            Path(
                "/Users/maxghenis/TheAxiomFoundation/_worktrees/"
                "axiom-rules-engine-canonical-loader-hard-cut"
            ),
            Path("/Users/maxghenis/TheAxiomFoundation/axiom-rules-engine"),
        )
        for axiom_rules_path in candidates:
            binary = axiom_rules_path / "target" / "debug" / "axiom-rules-engine"
            probe = (
                subprocess.run(
                    [str(binary), "compile", "--help"],
                    capture_output=True,
                    text=True,
                    check=False,
                )
                if binary.exists()
                else None
            )
            if probe is not None and "--rulespec-root" in (probe.stdout + probe.stderr):
                return axiom_rules_path
        pytest.skip("local explicit-root axiom-rules-engine binary is not built")

    def _write_rulespec_with_test(
        self,
        tmp_path: Path,
        *,
        expected_benefit: int,
    ) -> Path:
        repo = tmp_path / "rulespec-us"
        target = repo / "us/statutes/1/1.yaml"
        target.parent.mkdir(parents=True)
        target.write_text(
            """format: rulespec/v1
module:
  summary: Test companion execution.
rules:
  - name: threshold
    kind: parameter
    dtype: Money
    unit: USD
    versions:
      - effective_from: '2024-01-01'
        formula: '10'
  - name: benefit
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    versions:
      - effective_from: '2024-01-01'
        formula: income + threshold
"""
        )
        target.with_name("1.test.yaml").write_text(
            f"""- name: computes_derived_and_parameter_output
  period: 2026-01
  input:
    us:statutes/1/1#input.income: 5
  output:
    us:statutes/1/1#threshold: 10
    us:statutes/1/1#benefit: {expected_benefit}
"""
        )
        return repo

    def _args(self, repo: Path, *, json_output: bool):
        _write_test_rulespec_toolchain(repo)
        args = MagicMock()
        args.root = repo / "us"
        args.paths = []
        args.json = json_output
        args.axiom_rules_path = self._require_axiom_rules_path()
        args.rulespec_dependency_root = []
        return args

    def test_scalar_match_tolerates_decimal_residue(self):
        assert _rulespec_scalar_matches(
            {"kind": "decimal", "value": Decimal("19.999999999999999999999999992")},
            20,
        )
        assert _rulespec_scalar_matches(
            {"kind": "decimal", "value": Decimal("480.00000000000000000000000001")},
            480,
        )
        assert not _rulespec_scalar_matches(
            {"kind": "decimal", "value": Decimal("19.99")},
            20,
        )

