class TestCmdInventory:
    def test_inventory_counts_rulespec_files_and_kinds(self, capsys, tmp_path):
        statute_file = (
            tmp_path / "rulespec-us" / "us" / "statutes" / "7" / "2017" / "a.yaml"
        )
        statute_file.parent.mkdir(parents=True)
        statute_file.write_text(
            """
format: rulespec/v1
rules:
  - name: regular_allotment
    kind: derived
  - name: maximum_allotment
    kind: parameter
"""
        )
        test_file = statute_file.with_name("a.test.yaml")
        test_file.write_text(
            """
cases:
  - name: ignored
"""
        )

        composition_file = (
            tmp_path
            / "rulespec-us"
            / "us-co"
            / "policies"
            / "cdhs"
            / "snap"
            / "fy-2026-benefit-calculation.yaml"
        )
        composition_file.parent.mkdir(parents=True)
        composition_file.write_text(
            """
format: rulespec/v1
module:
  summary: Colorado SNAP FY 2026 benefit calculation composition.
rules:
  - name: final_allotment
    kind: derived
"""
        )

        relation_file = (
            tmp_path
            / "rulespec-us"
            / "us-co"
            / "regulations"
            / "10-ccr-2506-1"
            / "4.407.1.yaml"
        )
        relation_file.parent.mkdir(parents=True)
        relation_file.write_text(
            """
format: rulespec/v1
rules:
  - name: co_standard_deduction_restates_usda
    kind: source_relation
"""
        )
        program_spec = (
            tmp_path / "rulespec-us" / "us-co" / "programs" / "snap" / "fy-2026.yaml"
        )
        program_spec.parent.mkdir(parents=True)
        program_spec.write_text(
            "program: us-co/snap\nperiod: '2026-01'\noutputs: [snap_benefit]\n"
        )

        args = SimpleNamespace(root=tmp_path / "rulespec-us", json=True)

        cmd_inventory(args)

        output = json.loads(capsys.readouterr().out)
        assert output["total_files"] == 3
        assert output["source_provision_files"] == 2
        assert output["composition_files"] == 1
        assert output["total_rules"] == 4
        assert output["kind_counts"] == {
            "derived": 2,
            "parameter": 1,
            "source_relation": 1,
        }
        assert output["repos"] == [
            {
                "repo": "rulespec-us",
                "files": 3,
                "source_provision_files": 2,
                "composition_files": 1,
                "rules": 4,
                "roots": {"policies": 1, "regulations": 1, "statutes": 1},
                "kinds": {
                    "derived": 2,
                    "parameter": 1,
                    "source_relation": 1,
                },
            },
        ]

    def test_inventory_prints_human_summary(self, capsys, tmp_path):
        rulespec_file = (
            tmp_path / "rulespec-us" / "us" / "policies" / "usda" / "cola.yaml"
        )
        rulespec_file.parent.mkdir(parents=True)
        rulespec_file.write_text(
            """
format: rulespec/v1
rules:
  - name: snap_maximum_allotment
    kind: parameter
"""
        )
        args = SimpleNamespace(root=tmp_path / "rulespec-us", json=False)

        cmd_inventory(args)

        output = capsys.readouterr().out
        assert "RuleSpec inventory" in output
        assert "Files: 1 total; 1 source/provision; 0 composition" in output
        assert "Kinds: parameter=1" in output
        assert "rulespec-us: files=1" in output

    def test_inventory_rejects_workspace_and_flat_layouts(self, tmp_path):
        canonical = tmp_path / "rulespec-us/us/statutes/26/1.yaml"
        legacy_checkout = tmp_path / "rulespec-us-co/regulations/example.yaml"
        flat = tmp_path / "rulespec-us/statutes/26/2.yaml"
        for path in (canonical, legacy_checkout, flat):
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_text("format: rulespec/v1\nrules: []\n")

        with pytest.raises(ValueError, match="exact canonical rulespec-<country>"):
            cmd_inventory(SimpleNamespace(root=tmp_path, json=True))

        with pytest.raises(ValueError, match="exact canonical rulespec-<country>"):
            cmd_inventory(SimpleNamespace(root=tmp_path / "rulespec-us", json=True))

    def test_inventory_ignores_repository_root_programs(self, capsys, tmp_path):
        checkout = tmp_path / "rulespec-us"
        atomic = checkout / "us/statutes/26/1.yaml"
        atomic.parent.mkdir(parents=True)
        atomic.write_text("format: rulespec/v1\nrules: []\n")
        program = checkout / "programs/us/snap/fy-2026.yaml"
        program.parent.mkdir(parents=True)
        program.write_text("program: us/snap\nperiod: '2026-01'\noutputs: [benefit]\n")

        cmd_inventory(SimpleNamespace(root=checkout, json=True))

        output = json.loads(capsys.readouterr().out)
        assert output["total_files"] == 1
        assert output["repos"][0]["roots"] == {"statutes": 1}


class TestCmdIntervalTableAudit:
    def test_interval_table_audit_reports_reencoding_candidates(
        self,
        capsys,
        tmp_path,
    ):
        rulespec_file = (
            tmp_path
            / "rulespec-us"
            / "us"
            / "statutes"
            / "26"
            / "36B"
            / "b"
            / "3"
            / "A.yaml"
        )
        rulespec_file.parent.mkdir(parents=True)
        rulespec_file.write_text(
            """
format: rulespec/v1
module:
  summary: |-
    Applicable percentage table | Household income percent of poverty line | Initial | Final
    | Up to 133 | 0.021 | 0.021 |
    | 133 to 150 | 0.03 | 0.04 |
rules:
  - name: applicable_percentage_income_tier
    kind: derived
    entity: TaxUnit
    dtype: Integer
    period: Year
    versions:
      - effective_from: '2026-01-01'
        formula: |-
          if household_income_as_percent_of_poverty_line <= 133:
              0
          else:
              1
  - name: initial_applicable_percentage_by_tier
    kind: parameter
    dtype: Rate
    indexed_by: applicable_percentage_income_tier
    versions:
      - effective_from: '2026-01-01'
        values:
          0: 0.021
          1: 0.03
  - name: applicable_percentage
    kind: derived
    entity: TaxUnit
    dtype: Rate
    period: Year
    versions:
      - effective_from: '2026-01-01'
        formula: |-
          initial_applicable_percentage_by_tier[applicable_percentage_income_tier]
          + (household_income_as_percent_of_poverty_line - 133) / 17
"""
        )
        args = SimpleNamespace(
            root=tmp_path / "rulespec-us",
            include_selector_bounds=False,
            json=True,
            limit=50,
            fail_on_issues=False,
        )

        cmd_interval_table_audit(args)

        output = json.loads(capsys.readouterr().out)
        assert output["files_scanned"] == 1
        assert output["issue_count"] == 1
        assert output["blocking_issue_count"] == 1
        assert output["issues"][0]["repo"] == "rulespec-us"
        assert output["issues"][0]["path"] == "us/statutes/26/36B/b/3/A.yaml"
        assert output["issues"][0]["kind"] == "non_selector_interval_bound_literal"
        assert output["issues"][0]["literal"] == "133"

