    def test_apply_overlay_validation_fills_dependent_inputs_from_baseline(
        self, tmp_path
    ):
        output_root = tmp_path / "out"
        policy_repo = tmp_path / "rulespec-us" / "us"
        generated = output_root / "codex-test-model" / "statutes/26/63/c.yaml"
