class TestManifestCurrentState:
    """Applied manifests attest only the current generated state."""

    _CORPUS_CITATION_PATH = "be/statute/be/example"

    def _setup(self, tmp_path: Path):
        checkout = tmp_path / "rulespec-be"
        repo = checkout / "be"
        rule = repo / "statutes/be/example.yaml"
        rule.parent.mkdir(parents=True)
        release = _bind_test_corpus_release(
            checkout,
            tmp_path / "axiom-corpus",
            citation_path=self._CORPUS_CITATION_PATH,
            body="authoritative current-state source\n",
        )
        source_unit = resolve_corpus_source_unit(
            self._CORPUS_CITATION_PATH,
            release,
        )
        rule.write_text(
            "format: rulespec/v1\n"
            "module:\n"
            "  source_verification:\n"
            f"    corpus_citation_path: {self._CORPUS_CITATION_PATH}\n"
            f"    source_sha256: {source_unit.source_attestation['source_sha256']}\n"
            "rules: []\n"
        )
        generated = tmp_path / "gen/statutes/be/example.yaml"
        generated.parent.mkdir(parents=True)
        generated.write_text(rule.read_text())
        source_file = tmp_path / "eval-context/source.txt"
        source_file.parent.mkdir(parents=True)
        source_file.write_text(source_unit.body)
        context_manifest = source_file.with_name("context.json")
        context_manifest.write_text(
            json.dumps({"source_text_file": source_file.name}) + "\n"
        )
        source_attestation = {
            **source_unit.source_attestation,
            "generation_input_sha256": hashlib.sha256(
                source_unit.body.encode()
            ).hexdigest(),
        }
        return (
            checkout,
            repo,
            release.root,
            rule,
            generated,
            source_attestation,
            context_manifest,
        )

    def _make_result(
        self,
        output_file: Path,
        *,
        source_attestation: dict[str, object],
        context_manifest_file: Path,
        **overrides,
    ):
        defaults = dict(
            output_file=str(output_file),
            runner="codex:gpt-5.5",
            backend="codex",
            codex_cli_version="codex-cli fixture",
            codex_cli_sha256="c" * 64,
            model="gpt-5.5",
            tool="axiom-encode encode --apply",
            citation="be:statutes/be/example",
            generation_prompt_sha256="deadbeef",
            trace_file=None,
            context_manifest_file=str(context_manifest_file),
            source_attestation=source_attestation,
        )
        defaults.update(overrides)
        result = SimpleNamespace(**defaults)
        validation_payload = _signed_manifest_payload(
            {
                "schema_version": APPLIED_ENCODING_MANIFEST_SCHEMA,
                "backend": "codex",
                "source_attestation": {
                    **source_attestation,
                    "rulespec_root": "rulespec-be/be",
                },
                "applied_files": [],
            }
        )
        setattr(
            result,
            _APPLY_VALIDATION_SNAPSHOT_ATTR,
            {
                "manifest_validation_execution": validation_payload[
                    "validation_execution"
                ]
            },
        )
        return result

    def test_manifest_has_no_legacy_supersedes_chain(self, tmp_path):
        (
            checkout,
            repo,
            corpus_path,
            rule,
            gen,
            source_attestation,
            context_manifest,
        ) = self._setup(tmp_path)

        manifest = _write_applied_encoding_manifest(
            self._make_result(
                gen,
                source_attestation=source_attestation,
                context_manifest_file=context_manifest,
            ),
            output_root=tmp_path / "gen",
            policy_repo_path=repo,
            corpus_path=corpus_path,
            relative_output=Path("statutes/be/example.yaml"),
            applied_files=[rule],
            run_id="run-1",
            signing_broker=TEST_APPLY_SIGNING_BROKER,
            axiom_encode_git={"commit": "a" * 40},
        )
        payload = json.loads(manifest.read_text())
        assert manifest == (
            checkout / ".axiom/encoding-manifests/be/statutes/be/example.json"
        )
        assert payload["applied_files"] == [
            {
                "path": "be/statutes/be/example.yaml",
                "sha256": _sha256_file(rule),
            }
        ]
        assert payload["source_attestation"]["rulespec_root"] == "rulespec-be/be"
        assert "supersedes" not in payload
        assert payload["backend"] == "codex"

    def test_overwrite_replaces_prior_manifest(self, tmp_path):
        (
            _checkout,
            repo,
            corpus_path,
            rule,
            gen,
            source_attestation,
            context_manifest,
        ) = self._setup(tmp_path)

        # 1) Encoder-generated manifest.
        _write_applied_encoding_manifest(
            self._make_result(
                gen,
                source_attestation=source_attestation,
                context_manifest_file=context_manifest,
            ),
            output_root=tmp_path / "gen",
            policy_repo_path=repo,
            corpus_path=corpus_path,
            relative_output=Path("statutes/be/example.yaml"),
            applied_files=[rule],
            run_id="run-1",
            signing_broker=TEST_APPLY_SIGNING_BROKER,
            axiom_encode_git={"commit": "a" * 40},
        )

        rule.write_text(rule.read_text() + "# regenerated\n")
        gen.write_text(rule.read_text())
        manifest = _write_applied_encoding_manifest(
            self._make_result(
                gen,
                source_attestation=source_attestation,
                context_manifest_file=context_manifest,
                generation_prompt_sha256="feedface",
            ),
            output_root=tmp_path / "gen",
            policy_repo_path=repo,
            corpus_path=corpus_path,
            relative_output=Path("statutes/be/example.yaml"),
            applied_files=[rule],
            run_id="run-2",
            signing_broker=TEST_APPLY_SIGNING_BROKER,
            axiom_encode_git={"commit": "a" * 40},
        )
        payload = json.loads(manifest.read_text())
        assert payload["backend"] == "codex"
        assert payload["run_id"] == "run-2"
        assert payload["generation_prompt_sha256"] == "feedface"
        assert "supersedes" not in payload
        assert (
            _applied_encoding_manifest_signature_issue(
                payload, TEST_APPLY_SIGNING_BROKER
            )
            is None
        )


class TestAppliedManifestShrinkGuard:
    def _write_manifest(self, path: Path, applied_files: list[str]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(
            json.dumps(
                {
                    "applied_files": [
                        {"path": item, "sha256": "a" * 64} for item in applied_files
                    ]
                }
            )
        )

    def test_shrink_is_refused_and_names_dropped_files(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "manifest.json"
        self._write_manifest(manifest, ["be/rule.yaml", "be/rule.test.yaml"])

        with pytest.raises(RuntimeError) as exc_info:
            _require_applied_manifest_not_shrunk(
                manifest,
                new_applied_files={"be/rule.yaml"},
            )

        assert "be/rule.test.yaml" in str(exc_info.value)
        assert "--allow-shrink" in str(exc_info.value)
        assert "origin/main" in str(exc_info.value)

    def test_partial_overlap_is_refused_and_names_dropped_files(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "manifest.json"
        self._write_manifest(manifest, ["a.yaml", "b.yaml"])

        with pytest.raises(RuntimeError) as exc_info:
            _require_applied_manifest_not_shrunk(
                manifest,
                new_applied_files={"a.yaml", "x.yaml"},
            )

        message = str(exc_info.value)
        assert "b.yaml" in message
        assert "a.yaml" not in message
        assert "x.yaml" not in message

    def test_shrink_is_permitted_with_flag(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "manifest.json"
        self._write_manifest(manifest, ["be/rule.yaml", "be/rule.test.yaml"])

        _require_applied_manifest_not_shrunk(
            manifest,
            new_applied_files={"be/rule.yaml"},
            allow_shrink=True,
        )

    def test_equal_set_passes(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "manifest.json"
        files = {"be/rule.yaml", "be/rule.test.yaml"}
        self._write_manifest(manifest, sorted(files))

        _require_applied_manifest_not_shrunk(manifest, new_applied_files=files)

    def test_pure_extension_passes(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "manifest.json"
        self._write_manifest(manifest, ["be/rule.yaml"])

        _require_applied_manifest_not_shrunk(
            manifest,
            new_applied_files={"be/rule.yaml", "be/rule.test.yaml"},
        )

    def test_fresh_manifest_path_passes(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        _require_applied_manifest_not_shrunk(
            tmp_path / "new.json",
            new_applied_files={"be/rule.yaml"},
        )

    @pytest.mark.parametrize(
        ("raw", "problem"),
        [
            ("not json\n", "invalid JSON"),
            (json.dumps([]), "JSON object"),
            (json.dumps({"applied_files": [{"sha256": "a" * 64}]}), "applied_files[0]"),
        ],
    )
    def test_malformed_existing_manifest_requires_allow_shrink(
        self, tmp_path, raw, problem
    ):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "broken-manifest.json"
        manifest.write_text(raw)

        with pytest.raises(RuntimeError) as exc_info:
            _require_applied_manifest_not_shrunk(
                manifest,
                new_applied_files={"dk/statutes/composed/x.yaml"},
            )

        message = str(exc_info.value)
        assert str(manifest) in message
        assert problem in message
        assert "prior apply-manifest coverage" in message
        assert "--allow-shrink" in message
        _require_applied_manifest_not_shrunk(
            manifest,
            new_applied_files={"dk/statutes/composed/x.yaml"},
            allow_shrink=True,
        )

    def test_unreadable_existing_manifest_requires_allow_shrink(self, tmp_path):
        from axiom_encode.cli import _require_applied_manifest_not_shrunk

        manifest = tmp_path / "unreadable-manifest.json"
        manifest.write_text("{}\n")
        with (
            patch.object(Path, "read_text", side_effect=OSError("permission denied")),
            pytest.raises(RuntimeError) as exc_info,
        ):
            _require_applied_manifest_not_shrunk(
                manifest,
                new_applied_files={"dk/statutes/composed/x.yaml"},
            )

        message = str(exc_info.value)
        assert str(manifest) in message
        assert "unreadable" in message
        assert "permission denied" in message
        assert "--allow-shrink" in message

    def test_stage_normalizes_content_relative_files_to_checkout_manifest_paths(
        self, tmp_path
    ):
        from axiom_encode.cli import _stage_signed_apply_manifest

        checkout = tmp_path / "rulespec-dk"
        content_root = checkout / "dk"
        (checkout / ".axiom").mkdir(parents=True)
        (checkout / ".axiom/toolchain.toml").write_text("[toolchain]\n")
        (checkout / "known-validation-gaps.yaml").write_text("[]\n")
        manifest = checkout / ".axiom/encoding-manifests/dk/statutes/composed/x.json"
        self._write_manifest(
            manifest,
            [
                "dk/statutes/composed/x.yaml",
                "dk/statutes/composed/x.test.yaml",
            ],
        )
        planned = {
            Path("statutes/composed/x.yaml"): b"format: rulespec/v1\nrules: []\n",
            Path("statutes/composed/x.test.yaml"): b"[]\n",
        }

        def write_staged(_result, **kwargs):
            staged_root = kwargs["policy_repo_path"].parent
            applied = {
                path.relative_to(staged_root).as_posix()
                for path in kwargs["applied_files"]
            }
            from axiom_encode.cli import _require_applied_manifest_not_shrunk

            _require_applied_manifest_not_shrunk(
                kwargs["existing_manifest_path"],
                new_applied_files=applied,
                allow_shrink=kwargs["allow_shrink"],
            )
            staged_manifest = (
                staged_root / ".axiom/encoding-manifests/dk/statutes/composed/x.json"
            )
            staged_manifest.parent.mkdir(parents=True)
            staged_manifest.write_text("{}\n")
            return staged_manifest

        with (
            patch(
                "axiom_encode.cli._rulespec_checkout_root",
                return_value=checkout,
            ),
            patch(
                "axiom_encode.cli.load_rulespec_toolchain",
                return_value=SimpleNamespace(root=checkout),
            ),
            patch(
                "axiom_encode.cli._write_applied_encoding_manifest",
                side_effect=write_staged,
            ),
        ):
            relative, _raw = _stage_signed_apply_manifest(
                object(),
                output_root=tmp_path / "out",
                content_root=content_root,
                corpus_path=tmp_path / "corpus",
                relative_output=Path("statutes/composed/x.yaml"),
                planned=planned,
                run_id=None,
                signing_broker=TEST_APPLY_SIGNING_BROKER,
                axiom_encode_git={},
            )

        assert relative == Path(".axiom/encoding-manifests/dk/statutes/composed/x.json")

    def test_locked_recheck_refuses_manifest_expanded_after_staging(self, tmp_path):
        output_root = tmp_path / "out"
        checkout = tmp_path / "rulespec-dk"
        content_root = checkout / "dk"
        generated = output_root / "codex-test-model/statutes/composed/x.yaml"
        generated.parent.mkdir(parents=True)
        generated.write_text("format: rulespec/v1\nrules: []\n")
        content_root.mkdir(parents=True)
        manifest = checkout / ".axiom/encoding-manifests/dk/statutes/composed/x.json"
        manifest.parent.mkdir(parents=True)
        self._write_manifest(manifest, ["dk/statutes/composed/x.yaml"])
        result = SimpleNamespace(output_file=str(generated), backend="codex")
        setattr(
            result,
            _APPLY_VALIDATION_SNAPSHOT_ATTR,
            {"validation_execution": {"policy_content_files": {}}},
        )

        def install_after_expansion(_files, *, pre_install_check, **_kwargs):
            self._write_manifest(
                manifest,
                [
                    "dk/statutes/composed/x.yaml",
                    "dk/statutes/composed/x.test.yaml",
                ],
            )
            pre_install_check()

        with (
            patch("axiom_encode.cli._recover_apply_transaction"),
            patch(
                "axiom_encode.cli._require_clean_axiom_encode_git_provenance",
                return_value={},
            ),
            patch("axiom_encode.cli._stamp_generated_source_attestation_for_apply"),
            patch("axiom_encode.cli._enforce_canonical_concept_registry"),
            patch(
                "axiom_encode.cli.load_rulespec_local_corpus_release",
                return_value=object(),
            ),
            patch("axiom_encode.cli._require_unchanged_successful_apply_validation"),
            patch("axiom_encode.cli._enforce_no_apply_collision"),
            patch(
                "axiom_encode.cli._planned_apply_file_bytes",
                return_value=(
                    {Path("statutes/composed/x.yaml"): generated.read_bytes()},
                    False,
                ),
            ),
            patch(
                "axiom_encode.cli._require_planned_apply_bytes_match_validation_snapshot"
            ),
            patch(
                "axiom_encode.cli._stage_signed_apply_manifest",
                return_value=(
                    Path(".axiom/encoding-manifests/dk/statutes/composed/x.json"),
                    b"{}\n",
                ),
            ),
            patch(
                "axiom_encode.cli._require_staged_manifest_matches_validation_snapshot"
            ),
            patch("axiom_encode.cli._ensure_safe_apply_target"),
            patch(
                "axiom_encode.cli._install_apply_transaction",
                side_effect=install_after_expansion,
            ),
            pytest.raises(RuntimeError, match="x.test.yaml"),
        ):
            _apply_generated_encoding_result(
                result,
                output_root=output_root,
                policy_repo_path=content_root,
                corpus_path=tmp_path / "corpus",
                signing_broker=TEST_APPLY_SIGNING_BROKER,
            )


class TestManifestCensus:
    """Per-repo generated-provenance census stat (encode#1053, item 5)."""

    def _repo(self, tmp_path: Path) -> Path:
        repo = tmp_path / "rulespec-be"
        (repo / "be/statutes/be").mkdir(parents=True)
        _write_test_rulespec_toolchain(
            repo,
            release_content_sha256="e" * 64,
        )
        return repo

    def _add_rule(self, repo: Path, rel: str) -> Path:
        path = repo / "be" / rel
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text("format: rulespec/v1\nrules: []\n")
        return path

    def _add_manifest(self, repo: Path, rel: str, *, backend: str) -> None:
        rule = repo / "be" / rel
        manifest = (
            repo / ".axiom/encoding-manifests/be" / Path(rel).with_suffix(".json")
        )
        manifest.parent.mkdir(parents=True, exist_ok=True)
        source_attestation = None
        if backend in {"claude", "codex", "openai", "deterministic"}:
            rule.write_text(
                f"""format: rulespec/v1
module:
  source_verification:
    corpus_citation_path: be/statute/be/example
    source_sha256: {"a" * 64}
rules: []
"""
            )
            source_attestation = _complete_source_attestation("be/statute/be/example")
            source_attestation["rulespec_root"] = "rulespec-be/be"
        payload = {
            "schema_version": APPLIED_ENCODING_MANIFEST_SCHEMA,
            "backend": backend,
            "applied_files": [{"path": f"be/{rel}", "sha256": _sha256_file(rule)}],
        }
        if source_attestation is not None:
            payload["source_attestation"] = source_attestation
        manifest.write_text(json.dumps(_signed_manifest_payload(payload)) + "\n")

    def test_census_treats_legacy_deterministic_as_unmanifested(self, tmp_path):
        from axiom_encode.cli import _manifest_census

        repo = self._repo(tmp_path)
        self._add_rule(repo, "statutes/be/encoded.yaml")
        self._add_manifest(repo, "statutes/be/encoded.yaml", backend="codex")
        self._add_rule(repo, "statutes/be/legacy.yaml")
        self._add_manifest(
            repo,
            "statutes/be/legacy.yaml",
            backend="deterministic",
        )
        self._add_rule(repo, "statutes/be/bare.yaml")  # no manifest

        with patch.dict(
            os.environ,
            {APPLIED_ENCODING_SIGNING_PUBLIC_KEY_ENV: TEST_APPLY_PUBLIC_KEY_B64},
        ):
            census = _manifest_census(
                repo, roots=("policies", "regulations", "statutes")
            )

        assert census["total"] == 3
        assert census["encoder"] == 1
        assert "deterministic" not in census
        assert census["unmanifested"] == 2
        assert census["encoder_pct"] == pytest.approx(33.3, abs=0.1)
        assert "be/statutes/be/bare.yaml" in census["unmanifested_paths"]
        assert "be/statutes/be/legacy.yaml" in census["unmanifested_paths"]

    def test_census_counts_legislation_root(self, tmp_path):
        from axiom_encode.cli import _manifest_census

        repo = self._repo(tmp_path)
        self._add_rule(repo, "legislation/ukpga/2026/1.yaml")

        census = _manifest_census(repo, roots=("legislation",))

        assert census["total"] == 1
        assert census["unmanifested"] == 1
        assert census["unmanifested_paths"] == ["be/legislation/ukpga/2026/1.yaml"]

    def test_census_badge_json_shape(self, tmp_path, capsys):
        repo = self._repo(tmp_path)
        self._add_rule(repo, "statutes/be/encoded.yaml")
        self._add_manifest(repo, "statutes/be/encoded.yaml", backend="codex")

        args = SimpleNamespace(
            repo=repo,
            roots=" ".join(["policies", "regulations", "statutes"]),
            json=False,
            badge=True,
            out=None,
        )
        with patch.dict(
            os.environ,
            {APPLIED_ENCODING_SIGNING_PUBLIC_KEY_ENV: TEST_APPLY_PUBLIC_KEY_B64},
        ):
            cmd_manifest_census(args)

        badge = json.loads(capsys.readouterr().out)
        assert badge["schemaVersion"] == 1
        assert badge["label"] == "encoder-generated"
        assert badge["message"].startswith("100.0%")
        assert badge["color"] == "brightgreen"

    def test_census_writes_out_file(self, tmp_path):
        repo = self._repo(tmp_path)
        self._add_rule(repo, "statutes/be/encoded.yaml")
        self._add_manifest(repo, "statutes/be/encoded.yaml", backend="codex")
        out = tmp_path / "badges/encoder.json"

        args = SimpleNamespace(
            repo=repo,
            roots=" ".join(["policies", "regulations", "statutes"]),
            json=False,
            badge=True,
            out=out,
        )
        with patch.dict(
            os.environ,
            {APPLIED_ENCODING_SIGNING_PUBLIC_KEY_ENV: TEST_APPLY_PUBLIC_KEY_B64},
        ):
            cmd_manifest_census(args)

        assert out.exists()
        badge = json.loads(out.read_text())
        assert badge["schemaVersion"] == 1

    def test_census_json_attests_capture_time(self, tmp_path, capsys):
        repo = self._repo(tmp_path)
        self._add_rule(repo, "statutes/be/encoded.yaml")
        self._add_manifest(
            repo,
            "statutes/be/encoded.yaml",
            backend="codex",
        )
        args = SimpleNamespace(
            repo=repo,
            roots="policies regulations statutes",
            json=True,
            badge=False,
            out=None,
        )

        with patch.dict(
            os.environ,
            {APPLIED_ENCODING_SIGNING_PUBLIC_KEY_ENV: TEST_APPLY_PUBLIC_KEY_B64},
        ):
            cmd_manifest_census(args)

        census = json.loads(capsys.readouterr().out)
        assert census["captured_at"].endswith("Z")


def test_initial_encode_outcome_records_multigate_validation_failures():
    from axiom_encode.cli import _initial_encode_outcome

    metrics = SimpleNamespace(
        compile_issues=["Axiom rules engine compile failed: bad formula"],
        ci_issues=[
            "Proof atom missing path: rule `x` proof atom 0 must declare `path`."
        ],
        numeric_occurrence_issues=[
            "Ungrounded generated numeric literal: 0.15 does not appear as a substantive numeric value in the source text."
        ],
        generalist_review_issues=[],
        policyengine_issues=[],
    )
    outcome = _initial_encode_outcome(
        SimpleNamespace(
            success=False,
            error="Generated RuleSpec failed CI validation",
            metrics=metrics,
        ),
        apply_requested=False,
    )

    assert [item["gate"] for item in outcome["validation_failures"]] == [
        "compile",
        "ci",
        "numeric_occurrence",
    ]
    assert outcome["validation_failure_counts"] == {
        "compile:compile": 1,
        "ci:proof_atoms": 1,
        "numeric_occurrence:ungrounded_literal": 1,
    }
    assert "validation_failures_truncated" not in outcome


def test_initial_encode_outcome_success_omits_validation_failure_keys():
    from axiom_encode.cli import _initial_encode_outcome

    outcome = _initial_encode_outcome(
        SimpleNamespace(
            success=True, error=None, metrics=SimpleNamespace(ci_issues=["ignored"])
        ),
        apply_requested=False,
    )

    assert not any(key.startswith("validation_failure") for key in outcome)


def test_initial_encode_outcome_telemetry_error_never_propagates():
    from axiom_encode.cli import _initial_encode_outcome

    with patch(
        "axiom_encode.cli.summarize_validation_failures",
        side_effect=RuntimeError("telemetry broke"),
    ):
        outcome = _initial_encode_outcome(
            SimpleNamespace(
                success=False,
                error="Generated RuleSpec failed CI validation",
                metrics=SimpleNamespace(ci_issues=["No tests found."]),
            ),
            apply_requested=False,
        )

    assert outcome["validation_failure_counts"] == {"telemetry:error": 1}


def test_overlay_validation_failures_replace_standalone_telemetry():
    from axiom_encode.cli import _replace_overlay_validation_failures

    outcome = {
        "apply_error": "Axiom rules engine compile failed: overlay bad",
        "validation_failures": [{"gate": "ci"}],
        "validation_failures_truncated": 7,
        "validation_failure_counts": {"ci:proof_atoms": 1},
    }
    issues = [
        "Axiom rules engine compile failed: overlay bad",
        "Proof atom missing path: rule `x` proof atom 0 must declare `path`.",
    ]
    _replace_overlay_validation_failures(outcome, issues)

    assert outcome["apply_error"] == issues[0]
    assert [item["gate"] for item in outcome["validation_failures"]] == [
        "overlay",
        "overlay",
    ]
    assert outcome["validation_failure_counts"] == {
        "overlay:compile": 1,
        "overlay:proof_atoms": 1,
    }
    assert "validation_failures_truncated" not in outcome


def test_overlay_validation_failures_keep_standalone_telemetry_when_no_issues():
    from axiom_encode.cli import _replace_overlay_validation_failures

    outcome = {
        "apply_error": "standalone_failed: Generated RuleSpec failed CI validation",
        "validation_failures": [
            {"gate": "ci", "message_class": "proof_atoms", "detail": "x"}
        ],
        "validation_failure_counts": {"ci:proof_atoms": 1},
    }
    _replace_overlay_validation_failures(outcome, [])

    assert outcome["validation_failure_counts"] == {"ci:proof_atoms": 1}
    assert [item["gate"] for item in outcome["validation_failures"]] == ["ci"]


def test_ci_entrypoint_is_registered():
    result = subprocess.run(
        [sys.executable, "-m", "axiom_encode.cli", "ci", "--help"],
        check=False,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
    )

    assert result.returncode == 0
    assert "--corpus-release-public-key" in result.stdout
    assert "--allow-ref-mismatch" in result.stdout
    assert "--allow-encoder-mismatch" in result.stdout
